from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from redis import Redis
import jwt
import os
from typing import Optional
from pydantic import BaseModel

app = FastAPI()
security = HTTPBearer()

# Redis connection
redis_client = Redis(
    host=os.getenv("REDIS_HOST", "localhost"),
    port=int(os.getenv("REDIS_PORT", 6379)),
    db=int(os.getenv("REDIS_DB", 0)),
    decode_responses=True,
    socket_connect_timeout=5,
    socket_timeout=5
)

# JWT configuration
JWT_SECRET = os.getenv("JWT_SECRET")
JWT_ALGORITHM = os.getenv("JWT_ALGORITHM", "HS256")

class TokenData(BaseModel):
    sub: str
    scope: Optional[str] = None

def validate_token(credentials: HTTPAuthorizationCredentials = Depends(security)) -> TokenData:
    """Validate OAuth 2.0 bearer token against Redis cache"""
    if not credentials:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Authorization header missing",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = credentials.credentials
    
    # Validate token format
    if not token or not token.startswith("Bearer "):
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    # Extract token
    auth_token = token[7:]  # Remove "Bearer " prefix
    
    # Check if token exists in Redis cache
    try:
        cached_token = redis_client.get(f"oauth_token:{auth_token}")
        if not cached_token:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
        
        # Validate JWT token
        try:
            payload = jwt.decode(auth_token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
            token_data = TokenData(sub=payload.get("sub"), scope=payload.get("scope"))
            return token_data
        except jwt.ExpiredSignatureError:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Token expired",
                headers={"WWW-Authenticate": "Bearer"},
            )
        except jwt.InvalidTokenError:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid token",
                headers={"WWW-Authenticate": "Bearer"},
            )
    except Exception:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token validation failed",
            headers={"WWW-Authenticate": "Bearer"},
        )

@app.get("/protected")
async def protected_endpoint(token_data: TokenData = Depends(validate_token)):
    """Protected endpoint requiring valid OAuth 2.0 token"""
    return {"message": f"Hello {token_data.sub}", "scope": token_data.scope}

@app.get("/health")
async def health_check():
    """Health check endpoint"""
    try:
        redis_client.ping()
        return {"status": "healthy"}
    except Exception:
        raise HTTPException(status_code=500, detail="Redis connection failed")